import os
from langfuse import Langfuse
from langfuse.decorators import observe

# 第1步：初始化 Langfuse 客户端 —— 自动从环境变量读取密钥与宿主地址，
# 之后所有被 observe 装饰的函数都会被上报，无需手动埋点
langfuse = Langfuse()

# 第2步：装饰入口函数 —— @observe 开启对该函数的自动追踪，
# 调用链上的子函数若也被装饰，会形成完整的父子调用树
@observe()  # 自动追踪函数调用
def agent_run(query: str) -> str:
    # LangFuse 自动记录：输入、输出、耗时、Token、成本
    # 子调用同样被追踪，从而拼出整条链路的可观测性数据
    thought = think(query)  # 被追踪
    result = execute(thought)  # 被追踪
    return result

# 第3步：追踪思考环节 —— 单独的 observe 让 think 作为 agent_run 的子节点，
